const useNotificationContext = () => {
  const [notificationElem, setNotificationElem] = useState<HTMLHuelNotificationElement | null>(null);
  const [notificationProps, setNotificationProps] = useState<NotificationProps | null>(null);

  useEffect(() => {
    const element = document.querySelector('huel-notification');
    if (element) {
      setNotificationElem(element as HTMLHuelNotificationElement);
    }
